import { useMemo } from "react";
import { ReactHookForm } from "../../components/forms/react-hook-form";
import { BackendErrorResponse } from "../../components/forms/hooks/useBackendErrors";
import { formService } from "./formService";
import { formConfig } from "./formConfig";
import { formSchema } from "./formSchema";

export default function ConditionalForm() {
  const schema = formSchema;

  const handleSubmit = async (data: Record<string, unknown>) => {
    await formService.submitForm(data);
  };

  return (
    <div className="container mx-auto py-8 max-w-3xl">
      <ReactHookForm config={formConfig} schema={schema} onSubmit={handleSubmit} />
    </div>
  );
}

import { z } from "zod";

const baseSchema = z.object({
  firstName: z.string().min(1, "First Name is required"),
  lastName: z.string().min(1, "Last Name is required"),
  email: z.email("Invalid email").min(1, "Email is required"),
  isCompany: z.boolean(),
  companyName: z.string().optional(),
  registrationNumber: z.string().optional(),
  taxId: z.string().optional(),
  companySize: z.string().optional(),
  accountType: z.string().optional(),
  billingEmail: z.preprocess((v) => (v === "" || v === null || v === undefined ? undefined : v), z.email("Invalid email").optional()),
  paymentMethod: z.string().optional(),
  accountManager: z.string().optional(),
  expectedUsers: z.coerce.number().optional(),
  customRequirements: z.string().optional(),
  services: z.array(z.string()).optional(),
  needsShipping: z.boolean(),
  street: z.string().optional(),
  shippingCity: z.string().optional(),
  shippingPostalCode: z.string().optional(),
  shippingCountry: z.string().optional(),
});

export const formSchema = baseSchema.superRefine((data, ctx) => {
  if (data.isCompany === true) {
    if (!data.companyName || (typeof data.companyName === "string" && data.companyName.length === 0)) {
      ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Company Name is required", path: ["companyName"] });
    }
  }
  if (data.isCompany === true) {
    if (!data.registrationNumber || (typeof data.registrationNumber === "string" && data.registrationNumber.length === 0)) {
      ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Registration Number is required", path: ["registrationNumber"] });
    }
  }
});

export type FormValues = z.infer<typeof formSchema>;

import axios from "axios";
import { BackendErrorResponse, BackendFieldError } from "../../components/forms/hooks/useBackendErrors";

const API_BASE = "/api";

/**
 * Normalize any backend payload to AfnoUI's expected shape:
 * { success: false, message: string, errors?: [{ field, message }] }
 *
 * If your API uses a different format, edit only this function.
 */
function normalizeBackendError(data: unknown): BackendErrorResponse {
  if (typeof data !== "object" || data === null) {
    return { success: false, message: "Server error", errors: [] };
  }

  const payload = data as Record<string, unknown>;
  const message =
    (typeof payload.message === "string" && payload.message) ||
    (typeof payload.error === "string" && payload.error) ||
    "Server error";

  let errors: BackendFieldError[] = [];

  // Shape A: { errors: [{ field, message }] }
  if (Array.isArray(payload.errors)) {
    errors = payload.errors
      .map((item) => {
        if (typeof item !== "object" || item === null) return null;
        const e = item as Record<string, unknown>;
        const field = typeof e.field === "string" ? e.field : (typeof e.path === "string" ? e.path : null);
        const text = typeof e.message === "string" ? e.message : null;
        return field && text ? { field, message: text } : null;
      })
      .filter((e): e is BackendFieldError => e !== null);
  }

  // Shape B: { fieldErrors: { email: "Invalid", password: ["Too short"] } }
  if (errors.length === 0 && typeof payload.fieldErrors === "object" && payload.fieldErrors !== null) {
    const map = payload.fieldErrors as Record<string, unknown>;
    errors = Object.entries(map).flatMap(([field, raw]) => {
      if (typeof raw === "string") return [{ field, message: raw }];
      if (Array.isArray(raw)) {
        return raw
          .filter((x): x is string => typeof x === "string" && x.length > 0)
          .map((message) => ({ field, message }));
      }
      return [];
    });
  }

  return { success: false, message, errors };
}

export const formService = {
  async submitForm(data: Record<string, unknown>): Promise<void> {
    try {
      await axios.post(`${API_BASE}/forms/submit`, data);
    } catch (error: unknown) {
      if (axios.isAxiosError(error) && error.response?.data !== undefined) {
        throw normalizeBackendError(error.response.data);
      }
      throw { success: false, message: "Network error — please try again", errors: [] } as BackendErrorResponse;
    }
  },
};

